spec.expr:
label_join(
  avg(
    sum(
      rate(container_cpu_usage_seconds_total{
        namespace=~"$namespace",
        pod=~"$component.*",
        pod=~"$pod",
        container=~"$container",
        image!~"registry.k8s.io/pause:3.10", 
        id=~".*.scope",
        pod!~"",
        container!~"" 
      }[1m])
    ) by (pod, container, namespace)
    /
    sum(
      kube_pod_container_resource_limits{
        resource=~"cpu",
        namespace=~"$namespace",
        pod=~"$component.*",
        pod=~"$pod",
        container=~"$container",
        pod!~"",
        container!~"" 
      }
    ) by (pod, container, namespace)
  )
  by (pod, container, namespace),
  "podcontainer",
  ":",
  "pod",
  "container"
)

